:root{
  --bg:#0f1724;
  --text-color:#eef2ff;
  --greeting-size:clamp(28px,8vw,96px);
}

*{box-sizing:border-box}
html,body{height:100%;margin:0;font-family:Inter, system-ui, -apple-system, 'Segoe UI', Roboto, 'Helvetica Neue', Arial}
body{background:linear-gradient(180deg,var(--bg),#071024 60%);color:var(--text-color);-webkit-font-smoothing:antialiased}

.container{min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px}

.hero{display:flex;flex-direction:column;align-items:center;text-align:center;margin-bottom:28px}
.greeting{
  margin:0;font-weight:800;font-size:var(--greeting-size);line-height:1;letter-spacing:-0.02em;
  background:linear-gradient(90deg,#FF3B30 0%,#FF9500 14%,#FFCC00 28%,#34C759 42%,#007AFF 56%,#5856D6 70%,#FF2D55 86%);
  -webkit-background-clip:text;background-clip:text;color:transparent;
  background-size:200% 100%;
  /* Subtle shimmer animation */
  animation: gradient-move 6s linear infinite;
}

.subtitle{margin:8px 0 0;color:rgba(238,242,255,0.8)}

.palette{width:100%;max-width:780px;margin-top:18px;padding:18px;border-radius:8px;background:rgba(255,255,255,0.02);box-shadow:0 1px 0 rgba(255,255,255,0.02) inset}
.palette h2{margin:0 0 12px;font-size:16px}
.swatches{display:flex;flex-wrap:wrap;gap:10px}
.swatch{flex:0 0 auto;padding:10px 12px;border-radius:6px;background:rgba(255,255,255,0.03);color:var(--text-color);font-weight:600}
.swatch::before{content:'';display:inline-block;width:14px;height:14px;margin-right:8px;border-radius:3px;vertical-align:middle;background:var(--color)}
.palette-note{margin-top:12px;color:rgba(238,242,255,0.8)}

.notes{width:100%;max-width:780px;margin-top:18px;padding:18px;border-radius:8px;background:rgba(0,0,0,0.18);color:rgba(238,242,255,0.95)}
.notes h2{margin:0 0 8px}
.notes ul{margin:0;padding-left:18px}

@keyframes gradient-move{
  0%{background-position:0% 50%}
  50%{background-position:100% 50%}
  100%{background-position:0% 50%}
}

/* Respect reduced motion */
@media (prefers-reduced-motion: reduce){
  .greeting{animation:none}
}

/* Responsive tweaks */
@media (max-width:520px){
  .greeting{font-size:clamp(28px,12vw,48px)}
  .swatch{padding:8px 10px}
}


--- tests/mockup.test.ts ---
import fs from 'fs';
import path from 'path';

describe('Mockup content checks', () => {
  const mockupPath = path.join(__dirname, '..', 'public', 'mockup.html');
  let content: string;

  beforeAll(() => {
    content = fs.readFileSync(mockupPath, 'utf8');
  });

  test('contains the primary message "Hello World"', () => {
    expect(content).toMatch(/Hello World/);
  });

  test('contains the expected color palette hex codes', () => {
    const hexes = ['#FF3B30', '#FF9500', '#FFCC00', '#34C759', '#007AFF', '#5856D6', '#FF2D55'];
    for (const hex of hexes) {
      expect(content).toContain(hex);
    }
  });

  test('includes a notes section that mentions animation', () => {
    expect(content.toLowerCase()).toMatch(/notes.*animation|animation/);
    // ensure the specific animation name is documented
    expect(content).toMatch(/gradient-move/);
  });

});


